const NO_MOVES: readonly string[] = [];
const speciesNameCache = new Map<number, readonly string[]>();

/** 種族が BDSP で覚える技名（日本語・重複なし）。全バケツの id 和集合を解決。 */
export function movesForSpecies(speciesId: number): readonly string[] {
  const cached = speciesNameCache.get(speciesId);
  if (cached) return cached;
  const ls = SPECIES_LEARNSET[speciesId];
  if (!ls) return NO_MOVES;
  const ids = new Set<number>([
    ...ls.levelUp.map(([id]) => id),
    ...ls.machine,
    ...ls.egg,
    ...ls.tutor,
    ...ls.other,
  ]);
  if (ids.size === 0) return NO_MOVES;
  const names = Array.from(ids, (id) => MOVES[id].name);
  speciesNameCache.set(speciesId, names);
  return names;
}

export interface ClassifiedLearnset {
  readonly levelUp: readonly { name: string; level: number }[];
  readonly machine: readonly string[];
  readonly egg: readonly string[];
  readonly tutor: readonly string[];
  readonly other: readonly string[];
}
const classifiedCache = new Map<number, ClassifiedLearnset | null>();
/** UI 用: 学習方法ごとに技名（とレベル）を解決。データ無し種族は null。 */
export function classifiedMovesForSpecies(speciesId: number): ClassifiedLearnset | null {
  if (classifiedCache.has(speciesId))
    return classifiedCache.get(speciesId)!;
  const ls = SPECIES_LEARNSET[speciesId];
  const result: ClassifiedLearnset | null = ls
    ? {
        levelUp: ls.levelUp.map(([id, level]) => ({ name: MOVES[id].name, level })),
        machine: ls.machine.map((id) => MOVES[id].name),
        egg: ls.egg.map((id) => MOVES[id].name),
        tutor: ls.tutor.map((id) => MOVES[id].name),
        other: ls.other.map((id) => MOVES[id].name),
      }
    : null;
  classifiedCache.set(speciesId, result);
  return result;
}

let nameToInfo: Map<string, MoveInfo> | null = null;
/** 技名から詳細を引く（将来の技詳細表示用）。 */
export function moveInfo(name: string): MoveInfo | undefined {
  if (!nameToInfo) {
    nameToInfo = new Map();
    for (const id of Object.keys(MOVES)) nameToInfo.set(MOVES[Number(id)].name, MOVES[Number(id)]);
  }
  return nameToInfo.get(name);
}
